import dspy

class OverfittingDetector:
    def __init__(self, module):
        self.module = module

    def detect(self, trainset, testset):
        train_scores = [self.module(ex).complete for ex in trainset[:10]]
        test_scores = [self.module(ex).complete for ex in testset[:10]]
        train_acc = sum(1 for s in train_scores if s == 'correct')
        test_acc = sum(1 for s in test_scores if s == 'correct')
        gap = (train_acc / 10) - (test_acc / 10)
        return {'overfit_score': gap, 'alert': gap > 0.2}

import dspy

def validate_cot_logic(thought_output):
    verifier = dspy.ChainOfThought('reasoning -> valid:bool')
    validation_prompt = f"Is this reasoning logically sound? {thought_output}"
    result = verifier(validation_prompt)
    return result.valid == 'yes' and 'fallacy' not in thought_output.lower()

