class EnsembleValidator(dspy.Module):
    def __init__(self):
        super().__init__()
        self.module1 = dspy.ChainOfThought(QA)
        self.module2 = dspy.ProgramOfThought(QA)

    def forward(self, question):
        pred1 = self.module1(question)
        pred2 = self.module2(question)
        # Validate agreement
        agreement = pred1.answer.lower() == pred2.answer.lower()
        if not agreement:
            raise ValueError(f"Module disagreement: {pred1.answer} vs {pred2.answer}")
        return pred1
